"""Emit BUCK.pydeer files for each package in the lockfile."""

from __future__ import annotations

import json
import logging
from dataclasses import dataclass
from io import StringIO
from pathlib import Path

from lockfile import Package
from wheels import ParsedWheel, Target

log = logging.getLogger(__name__)


_LICENSE = """\
# Copyright (c) Meta Platforms, Inc. and affiliates.
#
# This source code is licensed under both the MIT license found in the
# LICENSE-MIT file in the root directory of this source tree and the Apache
# License, Version 2.0 found in the LICENSE-APACHE file in the root directory
# of this source tree.
"""

_GENERATED_MARKER = "# @" + "generated by `pydeer buckify`"


@dataclass(frozen=True)
class PackageBuild:
    package: Package
    wheels_by_target: dict[str, ParsedWheel]
    third_party_dir_label: str
    """Repo-relative label prefix for cross-package deps, e.g.
    "//shim/third-party/pypi"."""


def _q(s: str) -> str:
    """Render `s` as a double-quoted Starlark string."""
    return json.dumps(s)


def _render_string_list(items: list[str], indent: str) -> str:
    if not items:
        return "[]"
    inner = "\n".join(f"{indent}    {_q(s)}," for s in items)
    return "[\n" + inner + f"\n{indent}]"


def _render_http_file(name: str, url: str, sha256: str) -> str:
    return (
        "http_file(\n"
        f"    name = {_q(name)},\n"
        f"    urls = [{_q(url)}],\n"
        f"    sha256 = {_q(sha256)},\n"
        f"    out = {_q(name)},\n"
        ")\n"
    )


def _render_binary_src(
    wheels_by_target: dict[str, ParsedWheel],
    targets: tuple[Target, ...],
) -> str:
    unique_wheel_urls = {pw.wheel.url for pw in wheels_by_target.values()}
    if len(unique_wheel_urls) == 1:
        only = next(iter(wheels_by_target.values()))
        return _q(":" + only.wheel.filename)

    by_name = {t.name: t for t in targets}
    os_groups: dict[str, list[Target]] = {}
    for tname in sorted(wheels_by_target):
        target = by_name[tname]
        os_key = target.select_keys[0]
        os_groups.setdefault(os_key, []).append(target)

    lines: list[str] = ["select({"]
    for os_key in sorted(os_groups):
        targets_in_group = os_groups[os_key]
        is_flat = all(len(t.select_keys) == 1 for t in targets_in_group)
        if is_flat:
            t = targets_in_group[0]
            wheel = wheels_by_target[t.name].wheel
            lines.append(
                f"        {_q(os_key)}: {_q(':' + wheel.filename)},"
            )
        else:
            lines.append(f"        {_q(os_key)}: select({{")
            for t in targets_in_group:
                cpu_key = t.select_keys[1]
                wheel = wheels_by_target[t.name].wheel
                lines.append(
                    f"            {_q(cpu_key)}: {_q(':' + wheel.filename)},"
                )
            lines.append("        }),")
    lines.append("    })")
    return "\n".join(lines)


def _render_deps(package: Package, third_party_dir_label: str) -> list[str]:
    return sorted(
        f"{third_party_dir_label}/{d.name}:{d.name}" for d in package.deps
    )


def render_buck_file(
    build: PackageBuild,
    targets: tuple[Target, ...],
) -> str:
    out = StringIO()
    out.write(_LICENSE)
    out.write("\n")
    out.write(_GENERATED_MARKER + "\n\n")
    out.write(
        'load("@prelude//:rules.bzl", "http_file", "prebuilt_python_library")\n\n'
    )
    out.write('oncall("open_source")\n\n')

    seen_urls: set[str] = set()
    ordered_wheels: list[ParsedWheel] = []
    for tname in sorted(build.wheels_by_target):
        pw = build.wheels_by_target[tname]
        if pw.wheel.url in seen_urls:
            continue
        seen_urls.add(pw.wheel.url)
        ordered_wheels.append(pw)
    ordered_wheels.sort(key=lambda pw: pw.wheel.filename)

    for pw in ordered_wheels:
        out.write(_render_http_file(pw.wheel.filename, pw.wheel.url, pw.wheel.sha256))
        out.write("\n")

    binary_src = _render_binary_src(build.wheels_by_target, targets)
    deps = _render_deps(build.package, build.third_party_dir_label)

    out.write("prebuilt_python_library(\n")
    out.write(f"    name = {_q(build.package.name)},\n")
    out.write(f"    binary_src = {binary_src},\n")
    out.write(f"    deps = {_render_string_list(deps, '    ')},\n")
    out.write('    visibility = ["PUBLIC"],\n')
    out.write(")\n")

    return out.getvalue()


def write_package(
    build: PackageBuild,
    targets: tuple[Target, ...],
    out_root: Path,
) -> Path:
    pkg_dir = out_root / build.package.name
    pkg_dir.mkdir(parents=True, exist_ok=True)
    out_path = pkg_dir / "BUCK.pydeer"
    rendered = render_buck_file(build, targets)
    out_path.write_text(rendered)
    log.debug("wrote %s", out_path)
    return out_path
